// src/pages/MarketPage.jsx
import React, { useEffect, useState } from "react";
import api from "../api/backend";
import mongoClient from "../api/mongoFrontend";

const MarketPage = () => {
  const [rows, setRows] = useState([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState("");

  useEffect(() => {
    const fetchMarket = async () => {
      try {
        // Prefer backend Mongo proxy first
        try {
          const res = await api.get('/mongo/market');
          console.debug('mongo/market response status:', res.status, 'length:', Array.isArray(res.data) ? res.data.length : 'n/a');
          if (Array.isArray(res.data) && res.data.length) {
            console.debug('Using backend proxy /mongo/market with', res.data.length, 'rows');
            setRows(res.data);
            setLoading(false);
            return;
          }
        } catch (e) {
          console.debug('Backend mongo proxy failed or returned empty, trying other sources:', e && e.message ? e.message : e);
        }

        // Fallback: try direct Atlas Data API via client helper (if configured)
        try {
          const docs = await mongoClient.getMarketDocuments({ collectionName: 'stocks' });
          console.debug('client Data API docs length:', Array.isArray(docs) ? docs.length : 'n/a');
          if (Array.isArray(docs) && docs.length) {
            const mapped = docs.map((d) => ({
              symbol: d.code || d.symbol || d._id,
              name: d.name || d.title || '',
              price: d.price || d.latest_price || 0,
              change: Number(d.change || 0),
              changePercent: Number(d.changePercent || d.change_percent || 0),
            }));
            setRows(mapped);
            setLoading(false);
            return;
          }
        } catch (err) {
          console.debug('Direct Mongo fetch failed, falling back to sample market API:', err && err.message ? err.message : err);
        }

        // Final fallback: previous market API (Yahoo Finance snapshot)
        const res2 = await api.get("/market");
        setRows(res2.data || []);
      } catch (err) {
        console.error(err);
        setError("Failed to load market data.");
      } finally {
        setLoading(false);
      }
    };
    fetchMarket();
  }, []);

  return (
    <div className="page-shell">
      <header className="header">
        <h1>Live Market Overview</h1>
        <p>Snapshot of key indices and benchmarks powered by Yahoo Finance.</p>
      </header>

      <section className="results-panel">
        <h2>Global Indices</h2>

        {loading && <p className="placeholder">Loading market data…</p>}
        {error && <div className="error-box">{error}</div>}

        {!loading && !error && (
          <table className="results-table">
            <thead>
              <tr>
                <th>Symbol</th>
                <th>Name</th>
                <th>Price</th>
                <th>Change</th>
                <th>Change %</th>
              </tr>
            </thead>
            <tbody>
              {rows.map((row, idx) => (
                <tr key={idx}>
                  <td>{row.symbol}</td>
                  <td>{row.name}</td>
                  <td>{row.price}</td>
                  <td className={row.change >= 0 ? "score-positive" : "score-negative"}>
                    {row.change.toFixed(2)}
                  </td>
                  <td className={row.changePercent >= 0 ? "score-positive" : "score-negative"}>
                    {row.changePercent.toFixed(2)}%
                  </td>
                </tr>
              ))}
            </tbody>
          </table>
        )}
      </section>
    </div>
  );
};

export default MarketPage;
